// Buscar Sujeto + preservar nombre/genero del webhook
// $input.item.json aquí = output del Webhook (100% fiable)
const raw = $input.item.json;
// El webhook puede llegar con body anidado o directo
const webhook = raw.body || raw;
const nombre  = (webhook.nombre_sujeto || '').trim();
const genero  = (webhook.genero || '').trim();
console.log('[Buscar] nombre:', nombre, '| genero:', genero);
if (!nombre) throw new Error('Webhook no envió nombre_sujeto');
const formula = encodeURIComponent('LOWER(TRIM({nombre}))=LOWER(TRIM("' + nombre + '"))');
const res = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.airtable.com/v0/{{AIRTABLE_BASE_ID}}/Subjects?filterByFormula=' + formula + '&maxRecords=1',
  headers: { 'Authorization': 'Bearer {{AIRTABLE_API_KEY}}' }
});
return {
  records: res.records || [],
  nombre_sujeto: nombre,
  genero: genero,
  idea_escena: webhook.idea_escena || '',
  tipo_escena: webhook.tipo_escena || '',
  localizacion: webhook.localizacion || '',
  hora_dia: webhook.hora_dia || '',
  accion: webhook.accion || '',
  camara: webhook.camara || '',
  tono_visual: webhook.tono_visual || '',
  formato_video: webhook.formato_video || 'hook',
  producto: webhook.producto || '',
  template_script: webhook.template_script || '',
  script_tts_override: webhook.script_tts_override || ''
};

// Calcular Rotación — lee de $input (viene de Buscar Sujeto Code node)
const inp = $input.item.json;
const nombre = inp.nombre_sujeto || '';
const genero  = inp.genero || 'hombre';
console.log('[Rotación] nombre:', nombre, '| genero:', genero);
const voicesFemale = [
  { name: 'Laura',    id: 'uQw4jpKzMLrZuo0RLPS9' },
  { name: 'Raquel',   id: '1eHrpOW5l98cxiSRjbzJ' },
  { name: 'Cristina', id: 'dNjJKg63Fr5AXwIdkATa' }
];
const voicesMale = [
  { name: 'Bernat', id: 'jadd0g0NRgNgE8nt4ofn' },
  { name: 'Volu',   id: 'w8u1dIxiWVelUtUQg1MB' },
  { name: 'Carlos', id: 'hvjsm0LgwcoD1EyrNAJI' }
];
const countRes = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.airtable.com/v0/{{AIRTABLE_BASE_ID}}/Subjects',
  headers: { 'Authorization': 'Bearer {{AIRTABLE_API_KEY}}' }
});
const records = countRes.records || [];
const femaleCount = records.filter(r => r.fields.genero === 'mujer').length;
const maleCount   = records.filter(r => r.fields.genero === 'hombre').length;
const nextFemaleVoice = voicesFemale[femaleCount % voicesFemale.length];
const nextMaleVoice   = voicesMale[maleCount % voicesMale.length];
return {
  nombre_sujeto_fijo: nombre,
  genero_fijo: genero,
  next_female_voice_id:   nextFemaleVoice.id,
  next_female_voice_name: nextFemaleVoice.name,
  next_male_voice_id:     nextMaleVoice.id,
  next_male_voice_name:   nextMaleVoice.name,
  localizacion: inp.localizacion || '',
  hora_dia: inp.hora_dia || '',
  accion: inp.accion || '',
  camara: inp.camara || '',
  tono_visual: inp.tono_visual || '',
  formato_video: inp.formato_video || 'hook',
  template_script: inp.template_script || '',
  script_tts_override: inp.script_tts_override || '',
  idea_escena: inp.idea_escena || '',
  tipo_escena: inp.tipo_escena || '',
  producto: inp.producto || ''
};

const raw = $input.item.json.content[0].text;
let clean = raw.replace(/^```[\w]*\n?/gm, '').replace(/\n?```$/gm, '').trim();
let s;
try { s = JSON.parse(clean); } catch(e) {
  const match = raw.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No JSON: ' + raw.substring(0,300));
  s = JSON.parse(match[0]);
}

// Leer nombre y género desde Calcular Rotación de Voz (propagados explícitamente)
const rotacion = $('Calcular Rotación de Voz').item.json;
const nombre   = rotacion.nombre_sujeto_fijo || s.nombre || 'Sin nombre';
const genero   = rotacion.genero_fijo || 'hombre';

const voicesFemale = ['uQw4jpKzMLrZuo0RLPS9','1eHrpOW5l98cxiSRjbzJ','dNjJKg63Fr5AXwIdkATa'];
const voicesMale   = ['jadd0g0NRgNgE8nt4ofn','w8u1dIxiWVelUtUQg1MB','hvjsm0LgwcoD1EyrNAJI'];
const esMujer      = genero === 'mujer';
const validVoices  = esMujer ? voicesFemale : voicesMale;

let voice_id = s.voice_id;
if (!validVoices.includes(voice_id)) {
  voice_id = esMujer ? rotacion.next_female_voice_id : rotacion.next_male_voice_id;
}

console.log('[Parsear] nombre:', nombre, '| genero:', genero, '| voice_id:', voice_id);

return {
  nombre, genero,
  descripcion_fisica: s.descripcion_fisica,
  outfit_fijo: s.outfit_fijo,
  estilo_visual: s.estilo_visual,
  voice_id,
  idea_escena: rotacion.idea_escena || '',
  record_id: null,
  localizacion: rotacion.localizacion || '',
  hora_dia: rotacion.hora_dia || '',
  accion: rotacion.accion || '',
  camara: rotacion.camara || '',
  tono_visual: rotacion.tono_visual || '',
  formato_video: rotacion.formato_video || 'hook',
  template_script: rotacion.template_script || '',
  script_tts_override: rotacion.script_tts_override || '',
  tipo_escena: rotacion.tipo_escena || '',
  producto: rotacion.producto || ''
};

// Merge — unir datos de sujeto + escena
// Lee TODO de $input.item.json — NUNCA usar $('NodeName') en Code nodes (task runner)
const inp = $input.item.json;
console.log('[Merge] input keys:', Object.keys(inp).join(', '));

let subject;

// Rama TRUE (sujeto existente): inp viene de Cargar Sujeto Existente (Set node)
// Rama FALSE (sujeto nuevo): inp viene de Guardar Sujeto en Airtable (HTTP node)
if (inp.record_id) {
  // Sujeto existente — todos los campos están en inp (Set node los propagó)
  subject = {
    record_id: inp.record_id,
    nombre: inp.nombre,
    descripcion_fisica: inp.descripcion_fisica,
    outfit_fijo: inp.outfit_fijo,
    estilo_visual: inp.estilo_visual,
    voice_id: inp.voice_id,
    foto_referencia: inp.foto_referencia || ''
  };
  // Marcar run en Airtable
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: 'https://api.airtable.com/v0/{{AIRTABLE_BASE_ID}}/Subjects/' + subject.record_id,
      headers: {
        'Authorization': 'Bearer {{AIRTABLE_API_KEY}}',
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ fields: { ultimo_uso: new Date().toISOString().split('T')[0] } })
    });
  } catch(e) { console.log('[Merge] Warning:', e.message); }
} else {
  // Sujeto nuevo — inp viene de Guardar Sujeto (Airtable response)
  // Los campos de escena están en el record guardado? No — están en campos del response.
  // Usamos los campos del response de Airtable + lo que venga
  subject = {
    record_id: inp.id || '',
    nombre: inp.fields?.nombre || inp.nombre || '',
    descripcion_fisica: inp.fields?.descripcion_fisica || inp.descripcion_fisica || '',
    outfit_fijo: inp.fields?.outfit_fijo || inp.outfit_fijo || '',
    estilo_visual: inp.fields?.estilo_visual || inp.estilo_visual || '',
    voice_id: inp.fields?.voice_id || inp.voice_id || '',
    foto_referencia: ''
  };
}

// Campos de escena — desde inp (propagados por Cargar Sujeto Existente en rama TRUE)
// Para rama FALSE necesitamos leerlos de la cadena. Como el HTTP Response de Airtable
// no los tiene, usamos los items previos via $items() como fallback
let escena = {};
if (inp.localizacion) {
  escena = inp;
} else {
  // Fallback: leer todos los items para encontrar los datos de escena
  try {
    const allItems = $input.all();
    for (const item of allItems) {
      if (item.json.localizacion) { escena = item.json; break; }
    }
  } catch(e) {}
}

console.log('[Merge] localizacion:', escena.localizacion || inp.localizacion);
console.log('[Merge] tono_visual:', escena.tono_visual || inp.tono_visual);
console.log('[Merge] camara:', escena.camara || inp.camara);

subject.tipo_escena = escena.tipo_escena || inp.tipo_escena || '';
subject.localizacion = escena.localizacion || inp.localizacion || '';
subject.hora_dia = escena.hora_dia || inp.hora_dia || '';
subject.accion = escena.accion || inp.accion || '';
subject.camara = escena.camara || inp.camara || '';
subject.tono_visual = escena.tono_visual || inp.tono_visual || '';
subject.formato_video = escena.formato_video || inp.formato_video || 'hook';
subject.producto = escena.producto || inp.producto || '';
subject.template_script = escena.template_script || inp.template_script || '';
subject.script_tts_override = escena.script_tts_override || inp.script_tts_override || '';
subject.idea_escena = escena.idea_escena || inp.idea_escena || '';

return subject;

