const raw = $input.item.json.content[0].text;

// Clean markdown backticks robustly
let clean = raw
  .replace(/^```[\w]*\n?/gm, '')
  .replace(/\n?```$/gm, '')
  .trim();

// Parse JSON
let p;
try {
  p = JSON.parse(clean);
} catch(e) {
  // Try extracting JSON object from response
  const match = raw.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No JSON found in Claude response: ' + raw.substring(0,300));
  try {
    p = JSON.parse(match[0]);
  } catch(e2) {
    throw new Error('JSON inválido: ' + raw.substring(0,300));
  }
}

const required = ['script_tts','prompt_frame_inicio','prompt_frame_fin','prompt_video_kling'];
for (const f of required) { if (!p[f]) throw new Error('Falta campo: ' + f); }

const klingPrompt = typeof p.prompt_video_kling === 'object'
  ? p.prompt_video_kling.full_prompt || JSON.stringify(p.prompt_video_kling)
  : p.prompt_video_kling;

const merge = $('Merge - Unir Ramas IF').item.json;

return {
  prompt_frame_inicio: p.prompt_frame_inicio,
  prompt_frame_fin: p.prompt_frame_fin,
  prompt_video_kling: klingPrompt,
  prompt_video_kling_full: p.prompt_video_kling,
  script_tts: p.script_tts,
  record_id: merge.record_id,
  nombre_sujeto: merge.nombre,
  estilo_visual: merge.estilo_visual,
  voice_id: merge.voice_id,
  formato_video: p.formato || merge.formato_video || '',
  tono_visual: merge.tono_visual || '',
  foto_referencia: merge.foto_referencia || '',
  localizacion: merge.localizacion || '',
  hora_dia: merge.hora_dia || '',
  camara: merge.camara || '',
  producto: merge.producto || ''
};

// 2A — NanoBanana: Multi-model fallback + reference image for consistency
const rawPrompt = $input.item.json.prompt_frame_inicio;
const tonoVisual = $input.item.json.tono_visual || '';
const fotoRef = $input.item.json.foto_referencia || '';

let stylePrefix = 'Shot on iPhone 15 Pro, natural light, no filters, no color grading, no post-processing.';
if (tonoVisual.includes('Fujifilm')) stylePrefix = 'Shot on Fujifilm X100V, photodocumentary style, fine grain, muted tones, flat color.';
else if (tonoVisual.includes('Kodak')) stylePrefix = 'Shot on Kodak Portra 400, 35mm film, warm analog tones, natural film grain.';
else if (tonoVisual.includes('cinematic')) stylePrefix = 'Cinematic editorial photography, hyper-realistic, sharp focus, vivid colors.';

const skinPrefix = ' Ultra-realistic skin: visible pores, slight skin texture irregularities, natural sebum shine, subtle imperfections. NOT 3D render, NOT CGI, NOT digital art, NOT smoothed skin, NOT airbrushed. VERTICAL 9:16 PORTRAIT. Real human being. ';

let prompt;
let refImageB64 = null;
let refImageMime = null;

if (fotoRef) {
  // Descargar foto de referencia para enviarla como imagen inline
  console.log('[NanoBanana] Descargando foto_referencia:', fotoRef.substring(0, 80));
  try {
    const imgRes = await this.helpers.httpRequest({
      method: 'GET',
      url: fotoRef,
      encoding: 'arraybuffer',
      returnFullResponse: true
    });
    refImageB64 = Buffer.from(imgRes.body).toString('base64');
    refImageMime = 'image/jpeg';
    prompt = 'SAME PERSON as in the reference image — IDENTICAL face, bone structure, skin tone, hair color, hair texture, facial hair, eye color, nose shape, lip shape, jawline. Change ONLY the scene, pose, and lighting as described below. ' + stylePrefix + skinPrefix + rawPrompt;
    console.log('[NanoBanana] Modo: imagen de referencia + prompt');
  } catch(e) {
    console.log('[NanoBanana] No se pudo descargar foto_referencia, usando solo texto:', e.message);
    prompt = stylePrefix + skinPrefix + rawPrompt;
  }
} else {
  prompt = stylePrefix + skinPrefix + rawPrompt;
  console.log('[NanoBanana] Modo: solo texto (primer run)');
}

const GKEY = '{{GOOGLE_AI_STUDIO_KEY}}';
const models = [
  'gemini-3-pro-image-preview',
  'gemini-2.0-flash-preview-image-generation',
  'gemini-2.0-flash-exp'
];

let lastError = '';
for (const model of models) {
  console.log('[NanoBanana] Probando modelo:', model);
  try {
    // Build parts: reference image (if available) + text prompt
    const parts = [];
    if (refImageB64) {
      parts.push({ inlineData: { mimeType: refImageMime, data: refImageB64 } });
    }
    parts.push({ text: prompt });

    const nbRes = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${GKEY}`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{ parts }],
        generationConfig: { responseModalities: ['IMAGE', 'TEXT'], temperature: 0.3 }
      }),
      returnFullResponse: true,
      ignoreHttpStatusErrors: true
    });

    if (nbRes.statusCode === 404) {
      lastError = `${model}: 404`;
      continue;
    }
    if (nbRes.statusCode >= 400) {
      const body = typeof nbRes.body === 'string' ? nbRes.body : JSON.stringify(nbRes.body);
      lastError = `${model}: ${nbRes.statusCode} ${body.substring(0,100)}`;
      continue;
    }

    const resBody = typeof nbRes.body === 'string' ? JSON.parse(nbRes.body) : nbRes.body;
    const resParts = resBody.candidates?.[0]?.content?.parts || [];
    const imgPart = resParts.find(p => p.inlineData);

    if (!imgPart) {
      lastError = `${model}: sin imagen en respuesta`;
      continue;
    }

    console.log('[NanoBanana] Imagen generada con modelo:', model, refImageB64 ? '(con referencia)' : '(sin referencia)');
    return {
      frame_inicio_b64: imgPart.inlineData.data,
      frame_inicio_mime: imgPart.inlineData.mimeType || 'image/jpeg',
      model_used: model,
      prompt_frame_fin: $input.item.json.prompt_frame_fin,
      prompt_video_kling: $input.item.json.prompt_video_kling,
      record_id: $input.item.json.record_id,
      nombre_sujeto: $input.item.json.nombre_sujeto,
      formato_video: $input.item.json.formato_video || '',
      localizacion: $input.item.json.localizacion || '',
      producto: $input.item.json.producto || '',
      voice_id: $input.item.json.voice_id,
      tono_visual: $input.item.json.tono_visual || '',
      foto_referencia: fotoRef
    };
  } catch(e) {
    console.log('[NanoBanana] Excepción en', model, ':', e.message);
    lastError = `${model}: ${e.message}`;
  }
}

throw new Error('Ningún modelo de Gemini funcionó. Último error: ' + lastError);

// 2B — NanoBanana Frame Fin (opcional)
// Si usar_frame_fin=true → genera frame_fin con descripción específica
// Si usar_frame_fin=false (default) → devuelve frame_inicio como ambos frames

const usar = $input.item.json.usar_frame_fin === true
  || String($input.item.json.usar_frame_fin).toLowerCase() === 'true';

const b64ref  = $input.item.json.frame_inicio_b64;
const mimeRef = $input.item.json.frame_inicio_mime;
const GKEY    = '{{GOOGLE_AI_STUDIO_KEY}}';

// Upload frame_inicio a Cloudinary (siempre necesario)
const uploadImg = async (b64, mime, tag) => {
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.cloudinary.com/v1_1/dte2qskyq/image/upload',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ file: 'data:' + mime + ';base64,' + b64, upload_preset: 'ai_pipeline', tags: [tag] }),
    returnFullResponse: true, ignoreHttpStatusErrors: true
  });
  const body = typeof res.body === 'string' ? JSON.parse(res.body) : res.body;
  if (res.statusCode >= 400) throw new Error('Cloudinary ' + tag + ': ' + JSON.stringify(body).substring(0,200));
  if (!body.secure_url) throw new Error('Cloudinary ' + tag + ' sin URL');
  return body;
};

const upInicio = await uploadImg(b64ref, mimeRef, 'frame_inicio');

if (!usar) {
  // Sin frame_fin: usar frame_inicio como ambos → Kling genera movimiento libre
  console.log('[2B] usar_frame_fin=false → solo frame_inicio');
  return {
    frame_inicio_url: upInicio.secure_url,
    frame_fin_url: null,
    frame_fin_generated: false,
    prompt_video_kling: $input.item.json.prompt_video_kling,
    record_id: $input.item.json.record_id,
    nombre_sujeto: $input.item.json.nombre_sujeto,
    formato_video: $input.item.json.formato_video || '',
    localizacion: $input.item.json.localizacion || '',
    producto: $input.item.json.producto || ''
  };
}

// Con frame_fin: generar imagen específica para la transición
const rawPromptFin = $input.item.json.frame_fin_descripcion
  || $input.item.json.prompt_frame_fin
  || '';

const tonoVisual = $input.item.json.tono_visual || '';
let styleTag = 'Shot on iPhone 15 Pro, natural light, no filters.';
if (tonoVisual.includes('Fujifilm')) styleTag = 'Shot on Fujifilm X100V, fine grain, muted tones.';
else if (tonoVisual.includes('Kodak')) styleTag = 'Shot on Kodak Portra 400, 35mm, warm analog.';
else if (tonoVisual.includes('cinematic')) styleTag = 'Cinematic editorial, sharp, vivid.';
const prefix = 'no earphones in ears. ' + styleTag + ' Hyperrealistic skin. NOT 3D, NOT CGI. VERTICAL 9:16. SAME CHARACTER as reference image — identical face, hair color, skin tone. Only change: ';
const prompt = prefix + rawPromptFin;

console.log('[2B] usar_frame_fin=true → generando frame_fin');

const nbRes = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-3-pro-image-preview:generateContent?key=' + GKEY,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    contents: [{ parts: [
      { inlineData: { mimeType: mimeRef, data: b64ref } },
      { text: prompt }
    ]}],
    generationConfig: { responseModalities: ['IMAGE', 'TEXT'], temperature: 0.2 }
  })
});

const parts = nbRes.candidates?.[0]?.content?.parts || [];
const imgPart = parts.find(p => p.inlineData);
if (!imgPart) throw new Error('NanoBanana 2B sin imagen. Response: ' + JSON.stringify(nbRes).substring(0,200));

const upFin = await uploadImg(imgPart.inlineData.data, imgPart.inlineData.mimeType || 'image/jpeg', 'frame_fin');

return {
  frame_inicio_url: upInicio.secure_url,
  frame_fin_url: upFin.secure_url,
  frame_fin_generated: true,
  prompt_video_kling: $input.item.json.prompt_video_kling,
  record_id: $input.item.json.record_id,
  nombre_sujeto: $input.item.json.nombre_sujeto,
  formato_video: $input.item.json.formato_video || '',
  localizacion: $input.item.json.localizacion || '',
  producto: $input.item.json.producto || ''
};

// Kling 3.0 I2V — Submit + Poll (sleep integrado)
const item = $input.item.json;
const frameInicioUrl = item.frame_inicio_url;
const frameFinUrl    = item.frame_fin_url;
const usarFrameFin   = item.frame_fin_generated === true;
const audioUrl       = item.audio_url || item.secure_url || item.url;
const promptVideo    = item.prompt_video_kling;
const recordId       = item.record_id;
const nombreSujeto   = item.nombre_sujeto;

if (!frameInicioUrl) throw new Error('Falta frame_inicio_url');
if (!audioUrl) throw new Error('Falta audio URL');

// Ensure transition rule is ALWAYS first in the prompt, then truncate
const transitionPrefix = 'The character is actively speaking and talking throughout the entire video, with clear visible mouth movements, natural jaw motion, and lip articulation as if delivering a speech directly to camera. Smooth cinematic transition from start reference image to end reference image. The video begins exactly as shown in the start frame and ends exactly as shown in the end frame. Maintain character identity, clothing, accessories and environment consistent with both reference images. ';
const rawPrompt = promptVideo || '';
const hasTransition = rawPrompt.toLowerCase().includes('smooth cinematic transition');
const fullPrompt = hasTransition ? rawPrompt : transitionPrefix + rawPrompt;
const promptTruncado = fullPrompt.substring(0, 1800);
const PIAPI_KEY = '{{PIAPI_API_KEY}}';

// SUBMIT
// end_image_url solo si usar_frame_fin=true
const endImg = usarFrameFin ? frameFinUrl : null;
const configs = [
  { version: '2.0', mode: 'pro', duration: 5, end_image_url: endImg },
  { version: '1.6', mode: 'pro', duration: 5, end_image_url: endImg },
  { version: '1.6', mode: 'std', duration: 5, end_image_url: endImg },
  { version: '1.5', mode: 'std', duration: 5, end_image_url: endImg },
];

const errors = [];
let taskId = null;

for (const cfg of configs) {
  const input = { prompt: promptTruncado, image_url: frameInicioUrl, duration: cfg.duration, version: cfg.version, aspect_ratio: '9:16', mode: cfg.mode };
  if (cfg.end_image_url) input.end_image_url = cfg.end_image_url;
  const label = `v${cfg.version}/${cfg.mode}/${cfg.duration}s`;
  try {
    const raw = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.piapi.ai/api/v1/task',
      headers: { 'x-api-key': PIAPI_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: 'kling', task_type: 'video_generation', input }),
      returnFullResponse: true,
      ignoreHttpStatusErrors: true
    });
    const body = typeof raw.body === 'string' ? JSON.parse(raw.body) : (raw.body || raw);
    console.log('[Kling Submit]', label, 'HTTP' + raw.statusCode + ':', JSON.stringify(body).substring(0, 200));
    if (raw.statusCode < 400) {
      taskId = body.data?.task_id || body.task_id;
      if (taskId) { console.log('[Kling] task_id:', taskId); break; }
    }
    errors.push(label + ' HTTP' + raw.statusCode + ': ' + JSON.stringify(body).substring(0, 150));
  } catch(e) {
    errors.push(label + ': ' + e.message.substring(0, 100));
  }
}

if (!taskId) throw new Error('Kling submit fallido:\n' + errors.join('\n'));

// SLEEP 3 minutos (inline, sin Wait node)
console.log('[Kling] Esperando 3 minutos antes de poll...');
await new Promise(r => setTimeout(r, 180000));
console.log('[Kling] Iniciando poll...');

// Recursive URL finder
function findVideoUrl(obj, path, depth) {
  if (depth > 8) return null;
  if (typeof obj === 'string' && obj.length > 10) {
    if (/\.(mp4|webm|mov)/i.test(obj) || obj.includes('storage.theapi') || obj.includes('cdn.kling')) {
      console.log('[Kling] URL en:', path);
      return obj;
    }
  }
  if (Array.isArray(obj)) {
    for (let i = 0; i < obj.length; i++) { const r = findVideoUrl(obj[i], path+'['+i+']', depth+1); if (r) return r; }
  }
  if (obj && typeof obj === 'object') {
    for (const k of Object.keys(obj)) { const r = findVideoUrl(obj[k], path+'.'+k, depth+1); if (r) return r; }
  }
  return null;
}

// POLL 35x15s = 525s
for (let i = 0; i < 35; i++) {
  await new Promise(r => setTimeout(r, 15000));
  const check = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.piapi.ai/api/v1/task/' + taskId,
    headers: { 'x-api-key': PIAPI_KEY }
  });
  const status = check.data?.status || check.status;
  console.log('[Kling Poll '+(i+1)+'/35] status:', status);
  if (status === 'completed') {
    let videoUrl = findVideoUrl(check, 'check', 0);
    if (!videoUrl) throw new Error('Kling completed sin URL: ' + JSON.stringify(check.data).substring(0, 300));
    if (videoUrl.startsWith('//')) videoUrl = 'https:' + videoUrl;
    console.log('[Kling] ✅ URL:', videoUrl.substring(0, 80));
    return [{ json: { kling_video_url: videoUrl, audio_url: audioUrl, record_id: recordId, nombre_sujeto: nombreSujeto, frame_inicio_url: frameInicioUrl, frame_fin_url: frameFinUrl, formato_video: item.formato_video || '', localizacion: item.localizacion || '', producto: item.producto || '' } }];
  }
  if (status === 'failed') throw new Error('Kling failed: ' + JSON.stringify(check.data).substring(0, 200));
}
throw new Error('Kling timeout. task_id: ' + taskId);

// WaveSpeed AI Lipsync-2-pro — expose error body
const klingVideoUrl = $input.item.json.kling_video_url;
const audioUrl      = $input.item.json.audio_url;
const WS_KEY = '{{WAVESPEED_API_KEY}}';

if (!klingVideoUrl) throw new Error('Falta kling_video_url');
if (!audioUrl) throw new Error('Falta audio_url');

// Subir Kling a Cloudinary
let videoUrl = klingVideoUrl;
try {
  const up = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.cloudinary.com/v1_1/dte2qskyq/video/upload',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ file: klingVideoUrl, upload_preset: 'ai_pipeline', resource_type: 'video' })
  });
  if (up.secure_url) videoUrl = up.secure_url;
} catch(e) {}

console.log('[WS] video:', videoUrl.substring(0, 100));
console.log('[WS] audio:', audioUrl.substring(0, 100));

// Probar todos los combos posibles en try/catch
const attempts = [
  { url: 'https://api.wavespeed.ai/api/v3/sync/lipsync-2-pro', body: { video: videoUrl, audio: audioUrl, sync_mode: 'cut_off', temperature: 0.3 } },
  { url: 'https://api.wavespeed.ai/api/v3/sync/lipsync-2-pro', body: { video: videoUrl, audio: audioUrl, sync_mode: 'cut_off' } },
  { url: 'https://api.wavespeed.ai/api/v3/sync/lipsync-2-pro', body: { video: videoUrl, audio: audioUrl } },
];

const results = [];
for (const att of attempts) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: att.url,
      headers: { 'Authorization': 'Bearer ' + WS_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify(att.body),
      returnFullResponse: true,
      ignoreHttpStatusErrors: true
    });
    const b = typeof r.body === 'string' ? r.body : JSON.stringify(r.body);
    console.log('[WS]', att.url.split('/').slice(-2).join('/'), JSON.stringify(att.body).substring(0,50), '→ HTTP' + r.statusCode + ':', b.substring(0, 200));
    results.push({ status: r.statusCode, body: b.substring(0, 200) });
    if (r.statusCode < 400) {
      const parsed = JSON.parse(b);
      const requestId = parsed.data?.id || parsed.id;
      if (requestId) {
        // Poll
        for (let i = 0; i < 25; i++) {
          await new Promise(r => setTimeout(r, 8000));
          const check = await this.helpers.httpRequest({
            method: 'GET',
            url: 'https://api.wavespeed.ai/api/v3/predictions/' + requestId + '/result',
            headers: { 'Authorization': 'Bearer ' + WS_KEY }
          });
          const status = check.data?.status || check.status;
          console.log('[WS Poll '+(i+1)+'] status:', status);
          if (status === 'completed') {
            const finalUrl = check.data?.outputs?.[0] || check.data?.output;
            if (!finalUrl) throw new Error('Sin URL final: ' + JSON.stringify(check.data).substring(0,200));
            return { video_final_url: finalUrl, record_id: $input.item.json.record_id, nombre_sujeto: $input.item.json.nombre_sujeto, frame_inicio_url: $input.item.json.frame_inicio_url, frame_fin_url: $input.item.json.frame_fin_url || null, formato_video: $input.item.json.formato_video || '', localizacion: $input.item.json.localizacion || '', producto: $input.item.json.producto || '',
      frame_fin_generated: $input.item.json.frame_fin_generated || false };
          }
          if (status === 'failed') throw new Error('WaveSpeed failed: ' + JSON.stringify(check.data).substring(0,200));
        }
      }
    }
  } catch(e) {
    const errStr = e.response?.data ? JSON.stringify(e.response.data) : e.message;
    console.log('[WS] Exception:', errStr.substring(0, 200));
    results.push({ exception: errStr.substring(0, 200) });
  }
}

throw new Error('WaveSpeed: todos fallaron. Resultados:\n' + results.map((r,i) => i + ': ' + JSON.stringify(r)).join('\n'));

// Feedback Loop — append video URL to Airtable + save foto_referencia on first run
const recordId = $input.item.json.record_id;
const videoUrl = $input.item.json.video_final_url;
const frameInicioUrl = $input.item.json.frame_inicio_url;
const frameFinUrl = $input.item.json.frame_fin_url || null;
const KEY = '{{AIRTABLE_API_KEY}}';
const BASE = 'https://api.airtable.com/v0/{{AIRTABLE_BASE_ID}}/Subjects/';

// 1. Read current record to get existing videos
const current = await this.helpers.httpRequest({
  method: 'GET',
  url: BASE + recordId,
  headers: { 'Authorization': 'Bearer ' + KEY }
});

const existingVideos = current.fields.videos_generados || [];
const newVideo = { url: videoUrl, filename: 'video_run' + ((current.fields.total_runs || 0) + 1) + '.mp4' };
const allVideos = [...existingVideos.map(v => ({ url: v.url })), newVideo];

const totalRuns = (current.fields.total_runs || 0) + 1;

// 2. Build fotos_generadas (attachments — always append new frame)
const existingFotos = current.fields.fotos_generadas || [];
const newFotos = [{ url: frameInicioUrl, filename: 'frame_inicio_run' + totalRuns + '.jpg' }];
if (frameFinUrl) newFotos.push({ url: frameFinUrl, filename: 'frame_fin_run' + totalRuns + '.jpg' });
const allFotos = [...existingFotos.map(f => ({ url: f.url })), ...newFotos];

// 3. Build patch fields
const patchFields = {
  videos_generados: allVideos,
  fotos_generadas: allFotos,
  total_runs: totalRuns,
  ultimo_uso: new Date().toISOString().split('T')[0]
};

// 4. Save foto_referencia on first run (lock the character's face)
if (!current.fields.foto_referencia && frameInicioUrl) {
  patchFields.foto_referencia = frameInicioUrl;
  console.log('[Feedback] Guardando foto_referencia (primer run):', frameInicioUrl.substring(0, 80));
}

await this.helpers.httpRequest({
  method: 'PATCH',
  url: BASE + recordId,
  headers: { 'Authorization': 'Bearer ' + KEY, 'Content-Type': 'application/json' },
  body: JSON.stringify({ fields: patchFields })
});

console.log('[Feedback] Run #' + totalRuns + ' guardado. Videos acumulados:', allVideos.length);
return $input.item.json;

// Fetch all subjects from Airtable — same key used in pipeline nodes above
const res = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://api.airtable.com/v0/{{AIRTABLE_BASE_ID}}/Subjects?fields%5B%5D=nombre&fields%5B%5D=genero&fields%5B%5D=total_runs&fields%5B%5D=ultimo_uso&fields%5B%5D=foto_referencia&sort%5B0%5D%5Bfield%5D=ultimo_uso&sort%5B0%5D%5Bdirection%5D=desc',
  headers: { 'Authorization': 'Bearer {{AIRTABLE_API_KEY}}' }
});

const subjects = (res.records || []).map(r => ({
  id: r.id,
  nombre: r.fields.nombre || '',
  genero: r.fields.genero || '',
  total_runs: r.fields.total_runs || 0,
  ultimo_uso: r.fields.ultimo_uso || null,
  foto_referencia: (Array.isArray(r.fields.foto_referencia) ? (r.fields.foto_referencia[0]?.url || r.fields.foto_referencia[0]?.thumbnails?.large?.url || '') : r.fields.foto_referencia || '')
}));

console.log('[Subjects API] Devolviendo', subjects.length, 'personajes');
return [{ json: { subjects } }];
